189	    private boolean waitCompleted() {
190	        try {
191	            synchronized (mLock) {
192	                while ((mCondition & COREDUMP_COMPLETED) != COREDUMP_COMPLETED)
193	                    mLock.wait();
194	            }
195	        } catch (InterruptedException e) {
196	            return false;
197	        }
198	        return true;
199	    }
